FROM jsonb_to_recordset('[{"id": "cap-109-english-reading-029", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-109-english-reading", "question_type": "single_choice", "question_text": "What can we learn from the letter?", "options": ["Too much melatonin can hurt teenagers’ brain.", "The brain stops making melatonin after 11 p.m.", "Sleeping longer helps the body make more melatonin.", "It is easier to fall asleep when the brain is making melatonin."], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": "cap-109-english-reading-passage-28", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "26792f0afea3", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 29, "raw_text": "29. What can we learn from the letter?\n    (A) Too much melatonin can hurt teenagers’ brain.\n    (B) The brain stops making melatonin after 11 p.m.\n    (C) Sleeping longer helps the body make more melatonin.\n    (D) It is easier to fall asleep when the brain is making melatonin.\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-english-reading-030", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-109-english-reading", "question_type": "single_choice", "question_text": "Below is some information from another study.\nWe studied 48 high school students and found that the students who went\nto bed earlier did better on their school tests. This is not only true for\nthose who slept nine hours, but also true for those who slept less. And\nsome of them agreed that they learned better in early morning classes.\nDo the ideas in Selena Bieber’s letter agree with the information?", "options": ["Yes, because her letter says it is better to sleep from 11 p.m. to 8 a.m.", "Yes, because her letter says getting up early is not helpful for learning.", "No, because her letter says students are asked to get to school by 7:30 a.m.", "No, because her letter says teenagers’ brains do not work well in early morning classes."], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": "cap-109-english-reading-passage-28", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "26792f0afea3", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 30, "raw_text": "30. Below is some information from another study.\n     We studied 48 high school students and found that the students who went\n     to bed earlier did better on their school tests. This is not only true for\n     those who slept nine hours, but also true for those who slept less. And\n     some of them agreed that they learned better in early morning classes.\n\n    Do the ideas in Selena Bieber’s letter agree with the information?\n    (A) Yes, because her letter says it is better to sleep from 11 p.m. to 8 a.m.\n    (B) Yes, because her letter says getting up early is not helpful for learning.\n    (C) No, because her letter says students are asked to get to school by 7:30 a.m.\n    (D) No, because her letter says teenagers’ brains do not work well in early morning classes.\n\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-english-reading-031", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-109-english-reading", "question_type": "single_choice", "question_text": "What can we learn about Kivalina?", "options": ["It is waiting to shine.", "It has become history.", "It is fighting for one last hope.", "It has given up its chance to rise."], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": "cap-109-english-reading-passage-31", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "26792f0afea3", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 31, "raw_text": "31. What can we learn about Kivalina?\n    (A) It is waiting to shine.\n    (B) It has become history.\n    (C) It is fighting for one last hope.\n    (D) It has given up its chance to rise.\n\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-english-reading-032", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-109-english-reading", "question_type": "single_choice", "question_text": "What does it mean when we say a place is uninhabitable?", "options": ["It is not big.", "It is not popular.", "It cannot be bought.", "It cannot be lived in."], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": "cap-109-english-reading-passage-31", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "26792f0afea3", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 32, "raw_text": "32. What does it mean when we say a place is uninhabitable?   \n    (A) It is not big.\n    (B) It is not popular.\n    (C) It cannot be bought.\n    (D) It cannot be lived in.\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-english-reading-033", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-109-english-reading", "question_type": "single_choice", "question_text": "What does the writer think about the Inuit people in Kivalina?", "options": ["Their way of living has been hurting the earth.", "They might not be able to get enough money to move their village.", "They should make the oil and power companies fix their problems.", "There are better ways than to move their village to somewhere else."], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": "cap-109-english-reading-passage-31", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "26792f0afea3", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 33, "raw_text": "33. What does the writer think about the Inuit people in Kivalina?  \n    (A) Their way of living has been hurting the earth.\n    (B) They might not be able to get enough money to move their village.\n    (C) They should make the oil and power companies fix their problems.\n    (D) There are better ways than to move their village to somewhere else.\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-english-reading-034", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-109-english-reading", "question_type": "single_choice", "question_text": "What does the reading say about the Arctic ice?", "options": ["The Arctic ice covered 10 km2 of Kivalina.", "The melting Arctic ice kills about 400 Inuit people each year.", "The Arctic ice helped the Inuit people in Kivalina during bad weather.", "The melting Arctic ice has given the Inuit people enough water to use."], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": "cap-109-english-reading-passage-31", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "26792f0afea3", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 34, "raw_text": "34. What does the reading say about the Arctic ice?      \n    (A) The Arctic ice covered 10 km2 of Kivalina.\n    (B) The melting Arctic ice kills about 400 Inuit people each year.\n    (C) The Arctic ice helped the Inuit people in Kivalina during bad weather.  \n    (D) The melting Arctic ice has given the Inuit people enough water to use.\n\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-english-reading-035", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-109-english-reading", "question_type": "single_choice", "question_text": "(A) what else you can do", "options": ["", "how you can enjoy it more", "how it will change your life", "what is the best way of commute for you"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": "cap-109-english-reading-passage-35", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "26792f0afea3", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": ["option_incomplete"], "parse_confidence": 0.75, "original_question_number": 35, "raw_text": "35. (A) what else you can do \t\t\t\n    (B) how you can enjoy it more\n    (C) how it will change your life \t\t\t\n    (D) what is the best way of commute for you\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-109-english-reading-036", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-109-english-reading", "question_type": "single_choice", "question_text": "(A) costs you money", "options": ["", "hurts your health", "makes traffic terrible", "kills the planet slowly"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": "cap-109-english-reading-passage-35", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26